@* Step indicator bar showing progress through the multi-step form *@

<nav class="step-indicator mb-4" aria-label="Application steps">
    <ol class="step-list d-flex list-unstyled justify-content-between p-0 m-0">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep && !isCompleted;
            var cssClass = isCurrent ? "step active" : isCompleted ? "step completed" : "step dimmed";
            var isClickable = isCompleted && !isCurrent;

            <li class="@cssClass text-center flex-fill position-relative">
                @if (isClickable)
                {
                    <button type="button" class="btn btn-link step-button p-0 text-decoration-none" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle d-inline-flex align-items-center justify-content-center rounded-circle mb-1">
                            <span class="step-check">&#10003;</span>
                        </span>
                        <span class="step-label d-block small">@StepNames[step - 1]</span>
                    </button>
                }
                else
                {
                    <div class="step-display">
                        <span class="step-circle d-inline-flex align-items-center justify-content-center rounded-circle mb-1">
                            @if (isCompleted)
                            {
                                <span class="step-check">&#10003;</span>
                            }
                            else
                            {
                                @step
                            }
                        </span>
                        <span class="step-label d-block small">@StepNames[step - 1]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator {
    border-bottom: 2px solid #e9ecef;
    padding-bottom: 1rem;
}

.step-list li::after {
    content: "";
    position: absolute;
    top: 18px;
    left: 50%;
    width: 100%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-list li:last-child::after {
    display: none;
}

.step-circle {
    width: 36px;
    height: 36px;
    font-size: 0.85rem;
    font-weight: 600;
    position: relative;
    z-index: 1;
    background: #e9ecef;
    color: #6c757d;
    border: 2px solid #dee2e6;
}

.step.active .step-circle {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.step.completed .step-circle {
    background: #198754;
    color: #fff;
    border-color: #198754;
}

.step.dimmed .step-label {
    color: #adb5bd;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step-button {
    color: inherit !important;
}

.step-button:hover .step-circle {
    opacity: 0.8;
}

.step-button:hover .step-label {
    text-decoration: underline !important;
}

