@using sv_61ee8d2994384ef0b3de67e401947b5f.Models

<div class="personal-info-step">
    <h4 class="mb-3">Personal Information</h4>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <input type="text" class="form-control" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
            @if (IsValidating)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Validating...</span>
            }
            else
            {
                <span>Next &raquo;</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (!Model.IsValid())
        {
            ErrorMessage = "Please fill in all required fields.";
            return;
        }

        IsValidating = true;
        try
        {
            var isEmailValid = await ValidateEmail(Model.Email);
            if (!isEmailValid)
            {
                ErrorMessage = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            IsValidating = false;
        }
    }
}

@using sv_61ee8d2994384ef0b3de67e401947b5f.Models

<div class="work-history-step">
    <h4 class="mb-3">Work History</h4>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryEditor Entry="Entries[index]"
                         EntryIndex="index"
                         ShowRemove="Entries.Count > 1"
                         OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="d-flex justify-content-between mt-3">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">&laquo; Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<WorkEntryModel> Entries { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (!Entries.All(e => e.IsValid()))
        {
            ErrorMessage = "Please fill in company, title, and start date for all work entries.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_61ee8d2994384ef0b3de67e401947b5f.Models

<div class="references-step">
    <h4 class="mb-3">References</h4>
    <p class="text-muted">Please provide 2–3 professional references.</p>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceEditor Reference="References[index]"
                         ReferenceIndex="index"
                         ShowRemove="References.Count > 2"
                         OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="d-flex justify-content-between mt-3">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">&laquo; Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (!References.All(r => r.IsValid()))
        {
            ErrorMessage = "Please fill in all fields for each reference.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_61ee8d2994384ef0b3de67e401947b5f.Models

<div class="review-step">
    <h4 class="mb-4">Review Your Application</h4>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    @if (SubmittedId.HasValue)
    {
        <div class="alert alert-success text-center py-4">
            <h5 class="alert-heading">&#10003; Application Submitted!</h5>
            <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. We'll be in touch soon.</p>
        </div>
    }
    else
    {
        <!-- Personal Info -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Personal Information</strong>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6"><strong>Name:</strong> @Model.Personal.FullName</div>
                    <div class="col-md-6"><strong>Email:</strong> @Model.Personal.Email</div>
                    <div class="col-md-6"><strong>Phone:</strong> @Model.Personal.Phone</div>
                    <div class="col-md-6"><strong>Address:</strong> @Model.Personal.Address</div>
                </div>
            </div>
        </div>

        <!-- Work History -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Work History</strong>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
            </div>
            <div class="card-body">
                @foreach (var entry in Model.WorkEntries)
                {
                    <div class="mb-3 pb-3 border-bottom last-no-border">
                        <div><strong>@entry.Title</strong> at @entry.Company</div>
                        <div class="text-muted small">
                            @entry.StartDate?.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </div>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <div class="mt-1">@entry.Description</div>
                        }
                    </div>
                }
            </div>
        </div>

        <!-- References -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>References</strong>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
            </div>
            <div class="card-body">
                @foreach (var reference in Model.References)
                {
                    <div class="mb-2">
                        <strong>@reference.Name</strong> (@reference.Relationship)
                        — @reference.Email, @reference.Phone
                    </div>
                }
            </div>
        </div>

        <!-- Cover Letter -->
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Cover Letter</strong>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(4)'>Edit</button>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;">@Model.CoverLetter</p>
            </div>
        </div>

        <div class="d-flex justify-content-between">
            <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">&laquo; Back</button>
            <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    <span>Submitting...</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public ApplicationFormModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnEditStep { get; set; }

    [Parameter, EditorRequired]
    public Func<Task<int>> SubmitApplication { get; set; } = default!;

    private bool IsSubmitting;
    private int? SubmittedId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;

        try
        {
            SubmittedId = await SubmitApplication();
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

