+        IsValidating = true;
+        try
+        {
+            var isEmailValid = await ValidateEmail(Model.Email);
+            if (!isEmailValid)
+            {
+                ErrorMessage = "Please enter a valid email address.";
+                return;
+            }
+
+            await OnNext.InvokeAsync();
+        }
+        finally
+        {
+            IsValidating = false;
+        }
+    }
+}
+

