@using sv_61ee8d2994384ef0b3de67e401947b5f.Models

<div class="review-step">
    <h4 class="mb-4">Review Your Application</h4>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    @if (SubmittedId.HasValue)
    {
        <div class="alert alert-success text-center py-4">
            <h5 class="alert-heading">&#10003; Application Submitted!</h5>
            <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. We'll be in touch soon.</p>
        </div>
    }
    else
    {
        <!-- Personal Info -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Personal Information</strong>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6"><strong>Name:</strong> @Model.Personal.FullName</div>
                    <div class="col-md-6"><strong>Email:</strong> @Model.Personal.Email</div>
                    <div class="col-md-6"><strong>Phone:</strong> @Model.Personal.Phone</div>
                    <div class="col-md-6"><strong>Address:</strong> @Model.Personal.Address</div>
                </div>
            </div>
        </div>

        <!-- Work History -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Work History</strong>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
            </div>
            <div class="card-body">
                @foreach (var entry in Model.WorkEntries)
                {
                    <div class="mb-3 pb-3 border-bottom last-no-border">
                        <div><strong>@entry.Title</strong> at @entry.Company</div>
                        <div class="text-muted small">
                            @entry.StartDate?.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </div>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <div class="mt-1">@entry.Description</div>
                        }
                    </div>
                }
            </div>
        </div>

        <!-- References -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>References</strong>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
            </div>
            <div class="card-body">
                @foreach (var reference in Model.References)
                {
                    <div class="mb-2">
                        <strong>@reference.Name</strong> (@reference.Relationship)
                        — @reference.Email, @reference.Phone
                    </div>
                }
            </div>
        </div>

        <!-- Cover Letter -->
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Cover Letter</strong>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(4)'>Edit</button>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;">@Model.CoverLetter</p>
            </div>
        </div>

        <div class="d-flex justify-content-between">
            <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">&laquo; Back</button>
            <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    <span>Submitting...</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public ApplicationFormModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnEditStep { get; set; }

    [Parameter, EditorRequired]
    public Func<Task<int>> SubmitApplication { get; set; } = default!;

    private bool IsSubmitting;
    private int? SubmittedId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;

        try
        {
            SubmittedId = await SubmitApplication();
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

