                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;

            case 5:
                <ReviewStep Model="_form"
                            OnBack="PreviousStep"
                            OnEditStep="GoToStep"
                            SubmitApplication="SubmitAsync" />
                break;
        }
    </div>
</div>

@code {
    private readonly ApplicationFormModel _form = new();
    private readonly HashSet<int> _completedSteps = [];
    private int _currentStep = 1;

    private void NextStep()
    {
        _completedSteps.Add(_currentStep);
        _currentStep = Math.Min(_currentStep + 1, 5);
    }

    private void PreviousStep()
    {
        _currentStep = Math.Max(_currentStep - 1, 1);
    }

    private void GoToStep(int step)
    {
        if (_completedSteps.Contains(step) || step == _currentStep)
        {
            _currentStep = step;
        }
    }

    private void UpdateCoverLetter(string value)
    {
        _form.CoverLetter = value;
    }

    private async Task<int> SubmitAsync()
    {
        var application = _form.ToRecord();
        return await ApplicationService.SubmitApplicationAsync(application);
    }
}
