@page "/apply"
@using sv_61ee8d2994384ef0b3de67e401947b5f.Models
@using sv_61ee8d2994384ef0b3de67e401947b5f.Services
@rendermode InteractiveServer

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (_currentStep)
        {
            case 1:
                <PersonalInfoStep Model="_form.Personal"
                                  OnNext="NextStep"
                                  ValidateEmail="ApplicationService.ValidateEmailAsync" />
                break;

            case 2:
                <WorkHistoryStep Entries="_form.WorkEntries"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;

            case 3:
                <ReferencesStep References="_form.References"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;

            case 4:
                <CoverLetterStep CoverLetter="_form.CoverLetter"
                                 CoverLetterChanged="UpdateCoverLetter"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;

            case 5:
                <ReviewStep Model="_form"
                            OnBack="PreviousStep"
                            OnEditStep="GoToStep"
                            SubmitApplication="SubmitAsync" />
                break;
        }
    </div>
</div>

@code {
    private readonly ApplicationFormModel _form = new();
    private readonly HashSet<int> _completedSteps = [];
    private int _currentStep = 1;

    private void NextStep()
    {
        _completedSteps.Add(_currentStep);
        _currentStep = Math.Min(_currentStep + 1, 5);
    }

    private void PreviousStep()
    {
        _currentStep = Math.Max(_currentStep - 1, 1);
    }

    private void GoToStep(int step)
    {
        if (_completedSteps.Contains(step) || step == _currentStep)
        {
            _currentStep = step;
        }
    }

    private void UpdateCoverLetter(string value)
    {
        _form.CoverLetter = value;
    }

    private async Task<int> SubmitAsync()
    {
        var application = _form.ToRecord();
        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

